# Technology Stack Recommendations

This document provides technology recommendations for building a fleet maintenance scheduling system, with rationale for each choice.

## Stack Overview

```typescript
interface RecommendedStack {
  backend: {
    primary: 'TypeScript + Node.js (Bun runtime)';
    solver: 'Python (HiGHS + OR-Tools)';
    api: 'Hono framework';
  };

  database: {
    primary: 'PostgreSQL 16+';
    timeSeries: 'TimescaleDB extension';
    cache: 'Redis';
  };

  frontend: {
    framework: 'React 18+ with TypeScript';
    meta: 'Next.js or Astro';
    visualization: 'ECharts';
  };

  infrastructure: {
    containers: 'Docker';
    orchestration: 'Docker Compose or Kubernetes';
    cloud: 'AWS/GCP/Azure agnostic';
  };
}
```

## Backend: TypeScript + Bun

### Why TypeScript

```typescript
interface TypeScriptBenefits {
  typeSafety: 'Catch errors at compile time';
  developer: 'Excellent IDE support, refactoring';
  ecosystem: 'Largest package ecosystem (npm)';
  hiring: 'Large developer pool';
  fullStack: 'Same language frontend and backend';
}
```

### Why Bun Runtime

```typescript
interface BunBenefits {
  performance: '3-4x faster than Node.js';
  native: 'TypeScript without transpilation';
  bundler: 'Built-in bundler and test runner';
  compatibility: 'Node.js API compatible';
  modern: 'ESM-first, Web APIs built-in';
}
```

### Setup Example

```bash
# Initialize Bun project
bun init

# Install dependencies
bun add hono drizzle-orm postgres zod
bun add -d typescript @types/node
```

```typescript
// src/index.ts
import { Hono } from 'hono';
import { cors } from 'hono/cors';
import { logger } from 'hono/logger';

const app = new Hono();

app.use('*', logger());
app.use('*', cors());

app.get('/health', (c) => c.json({ status: 'ok' }));

export default {
  port: process.env.PORT ?? 3000,
  fetch: app.fetch
};
```

## Solver: Python

### Why Python for Solver

```typescript
interface PythonSolverBenefits {
  libraries: 'Best optimization library support';
  highs: 'Native highspy bindings';
  ortools: 'Official Google OR-Tools support';
  scientific: 'NumPy, Pandas for data processing';
  academic: 'Optimization research uses Python';
}
```

### Integration Pattern

```typescript
// TypeScript calls Python solver via subprocess
import { spawn } from 'bun';

interface SolverInput {
  events: MaintenanceEvent[];
  periods: number[];
  capacity: number;
  timeLimit: number;
}

interface SolverOutput {
  status: string;
  schedule: Record<string, number>;
  objective: number;
  solveTime: number;
}

async function callSolver(input: SolverInput): Promise<SolverOutput> {
  const proc = spawn(['python3', 'solver/main.py'], {
    stdin: 'pipe',
    stdout: 'pipe',
    stderr: 'pipe'
  });

  // Send input
  proc.stdin.write(JSON.stringify(input));
  proc.stdin.end();

  // Read output
  const stdout = await new Response(proc.stdout).text();
  const stderr = await new Response(proc.stderr).text();

  const exitCode = await proc.exited;
  if (exitCode !== 0) {
    throw new Error(`Solver failed: ${stderr}`);
  }

  return JSON.parse(stdout);
}
```

```python
# solver/main.py
import sys
import json
import highspy

def solve(input_data: dict) -> dict:
    # Build and solve model
    h = highspy.Highs()
    h.silent()

    # ... model building ...

    h.run()

    return {
        'status': str(h.getModelStatus()),
        'schedule': extract_schedule(h),
        'objective': h.getInfo().objective_function_value,
        'solveTime': h.getInfo().run_time
    }

if __name__ == '__main__':
    input_data = json.load(sys.stdin)
    result = solve(input_data)
    print(json.dumps(result))
```

## Database: PostgreSQL

### Why PostgreSQL

```typescript
interface PostgreSQLBenefits {
  reliability: 'Battle-tested, ACID compliant';
  features: 'JSON, arrays, CTEs, window functions';
  extensions: 'TimescaleDB, PostGIS, pg_cron';
  performance: 'Excellent query optimizer';
  operational: 'Well-understood operations';
}
```

### Key Extensions

```sql
-- TimescaleDB for time-series metrics
CREATE EXTENSION IF NOT EXISTS timescaledb;

-- Enable for mileage history table
SELECT create_hypertable('mileage_readings', 'recorded_at');

-- pg_cron for scheduled jobs
CREATE EXTENSION IF NOT EXISTS pg_cron;

-- Schedule daily RUC calculation
SELECT cron.schedule('daily-ruc', '0 5 * * *',
  $$SELECT calculate_ruc()$$
);
```

### Schema Example

```typescript
// drizzle/schema.ts
import { pgTable, uuid, text, integer, timestamp, real } from 'drizzle-orm/pg-core';

export const assets = pgTable('assets', {
  id: uuid('id').primaryKey().defaultRandom(),
  externalId: text('external_id').unique(),
  name: text('name').notNull(),
  assetType: text('asset_type').notNull(),
  currentMileage: integer('current_mileage').default(0),
  status: text('status').default('active'),
  createdAt: timestamp('created_at').defaultNow(),
  updatedAt: timestamp('updated_at').defaultNow()
});

export const maintenanceTypes = pgTable('maintenance_types', {
  id: uuid('id').primaryKey().defaultRandom(),
  name: text('name').notNull(),
  intervalMileage: integer('interval_mileage'),
  intervalDays: integer('interval_days'),
  durationHours: real('duration_hours').notNull(),
  manHours: real('man_hours').notNull()
});

export const scheduledEvents = pgTable('scheduled_events', {
  id: uuid('id').primaryKey().defaultRandom(),
  assetId: uuid('asset_id').references(() => assets.id),
  maintenanceTypeId: uuid('maintenance_type_id').references(() => maintenanceTypes.id),
  scheduledWeek: integer('scheduled_week').notNull(),
  targetMileage: integer('target_mileage'),
  status: text('status').default('scheduled'),
  scheduleVersion: integer('schedule_version').notNull()
});
```

## Cache: Redis

### Why Redis

```typescript
interface RedisBenefits {
  speed: 'Microsecond latency';
  versatile: 'Cache, queue, pub/sub, sessions';
  simple: 'Easy to operate';
  scalable: 'Cluster mode for HA';
}
```

### Use Cases

```typescript
// Session caching
await redis.set(`session:${userId}`, JSON.stringify(session), 'EX', 3600);

// API response caching
const cached = await redis.get(`schedule:${scheduleId}`);
if (cached) return JSON.parse(cached);

// Job queue
await redis.lpush('solver:jobs', JSON.stringify(job));

// Pub/sub for real-time updates
redis.publish('schedule:updated', JSON.stringify({ scheduleId }));
```

## Frontend: React + Next.js

### Why React

```typescript
interface ReactBenefits {
  ecosystem: 'Largest component ecosystem';
  hiring: 'Most developers know React';
  tooling: 'Excellent development tools';
  flexibility: 'Works with any backend';
}
```

### Why Next.js

```typescript
interface NextJSBenefits {
  ssr: 'Server-side rendering for SEO and performance';
  routing: 'File-based routing';
  api: 'API routes for BFF pattern';
  optimization: 'Image, font, script optimization';
  deployment: 'Easy deployment to Vercel or self-host';
}
```

