   165‚Üí## Schedule Visualization
   166‚Üí
   167‚Üí### Gantt Chart
   168‚Üí
   169‚Üí```tsx
   170‚Üí// components/schedule/ScheduleGantt.tsx
   171‚Üíimport ReactECharts from 'echarts-for-react';
   172‚Üíimport { useMemo } from 'react';
   173‚Üí
   174‚Üíinterface ScheduleEvent {
   175‚Üí  id: string;
   176‚Üí  assetId: string;
   177‚Üí  assetName: string;
   178‚Üí  maintenanceType: string;
   179‚Üí  startDate: Date;
   180‚Üí  endDate: Date;
   181‚Üí  status: 'scheduled' | 'in_progress' | 'completed';
   182‚Üí}
   183‚Üí
   184‚Üíinterface ScheduleGanttProps {
   185‚Üí  events: ScheduleEvent[];
   186‚Üí  assets: string[];
   187‚Üí  startDate: Date;
   188‚Üí  endDate: Date;
   189‚Üí  onEventClick?: (event: ScheduleEvent) => void;
   190‚Üí}
   191‚Üí
   192‚Üíexport function ScheduleGantt({
   193‚Üí  events,
   194‚Üí  assets,
   195‚Üí  startDate,
   196‚Üí  endDate,
   197‚Üí  onEventClick
   198‚Üí}: ScheduleGanttProps) {
   199‚Üí  const option = useMemo(() => ({
   200‚Üí    tooltip: {
   201‚Üí      trigger: 'item',
   202‚Üí      formatter: (params: any) => {
   203‚Üí        const event = events[params.dataIndex];
   204‚Üí        return `
   205‚Üí          <strong>${event.assetName}</strong><br/>
   206‚Üí          ${event.maintenanceType}<br/>
   207‚Üí          ${formatDate(event.startDate)} - ${formatDate(event.endDate)}
   208‚Üí        `;
   209‚Üí      }
   210‚Üí    },
   211‚Üí    grid: {
   212‚Üí      left: 150,
   213‚Üí      right: 20,
   214‚Üí      top: 40,
   215‚Üí      bottom: 40
   216‚Üí    },
   217‚Üí    xAxis: {
   218‚Üí      type: 'time',
   219‚Üí      min: startDate.getTime(),
   220‚Üí      max: endDate.getTime(),
   221‚Üí      axisLabel: {
   222‚Üí        formatter: '{MMM} {d}'
   223‚Üí      }
   224‚Üí    },
   225‚Üí    yAxis: {
   226‚Üí      type: 'category',
   227‚Üí      data: assets,
   228‚Üí      axisLabel: {
   229‚Üí        width: 140,
   230‚Üí        overflow: 'truncate'
   231‚Üí      }
   232‚Üí    },
   233‚Üí    series: [{
   234‚Üí      type: 'custom',
   235‚Üí      renderItem: (params: any, api: any) => {
   236‚Üí        const event = events[params.dataIndex];
   237‚Üí        const yIndex = assets.indexOf(event.assetName);
   238‚Üí
   239‚Üí        const start = api.coord([event.startDate.getTime(), yIndex]);
   240‚Üí        const end = api.coord([event.endDate.getTime(), yIndex]);
   241‚Üí
   242‚Üí        const rectHeight = api.size([0, 1])[1] * 0.6;
   243‚Üí
   244‚Üí        return {
   245‚Üí          type: 'rect',
   246‚Üí          shape: {
   247‚Üí            x: start[0],
   248‚Üí            y: start[1] - rectHeight / 2,
   249‚Üí            width: end[0] - start[0],
   250‚Üí            height: rectHeight
   251‚Üí          },
   252‚Üí          style: {
   253‚Üí            fill: getEventColor(event.status),
   254‚Üí            stroke: '#333',
   255‚Üí            lineWidth: 1
   256‚Üí          }
   257‚Üí        };
   258‚Üí      },
   259‚Üí      data: events.map((e, i) => [e.startDate, e.endDate, i])
   260‚Üí    }]
   261‚Üí  }), [events, assets, startDate, endDate]);
   262‚Üí
   263‚Üí  return (
   264‚Üí    <ReactECharts
   265‚Üí      option={option}
   266‚Üí      style={{ height: Math.max(400, assets.length * 30) }}
   267‚Üí      onEvents={{
   268‚Üí        click: (params: any) => {
   269‚Üí          if (onEventClick && params.dataIndex !== undefined) {
   270‚Üí            onEventClick(events[params.dataIndex]);
   271‚Üí          }
   272‚Üí        }
   273‚Üí      }}
   274‚Üí    />
   275‚Üí  );
   276‚Üí}
   277‚Üí
   278‚Üífunction getEventColor(status: string): string {
   279‚Üí  switch (status) {
   280‚Üí    case 'completed': return '#10b981';
   281‚Üí    case 'in_progress': return '#3b82f6';
   282‚Üí    case 'scheduled': return '#f59e0b';
   283‚Üí    default: return '#6b7280';
   284‚Üí  }
   285‚Üí}
   286‚Üí```
