   417‚Üí## Real-Time Updates
   418‚Üí
   419‚Üí### SSE Hook
   420‚Üí
   421‚Üí```tsx
   422‚Üí// hooks/useRealTimeUpdates.ts
   423‚Üíimport { useEffect, useCallback } from 'react';
   424‚Üíimport { useQueryClient } from '@tanstack/react-query';
   425‚Üí
   426‚Üíinterface UseRealTimeUpdatesOptions {
   427‚Üí  scheduleId?: string;
   428‚Üí  onUpdate?: (data: unknown) => void;
   429‚Üí}
   430‚Üí
   431‚Üíexport function useRealTimeUpdates({ scheduleId, onUpdate }: UseRealTimeUpdatesOptions) {
   432‚Üí  const queryClient = useQueryClient();
   433‚Üí
   434‚Üí  useEffect(() => {
   435‚Üí    if (!scheduleId) return;
   436‚Üí
   437‚Üí    const eventSource = new EventSource(
   438‚Üí      `/api/v1/schedules/${scheduleId}/updates`
   439‚Üí    );
   440‚Üí
   441‚Üí    eventSource.onmessage = (event) => {
   442‚Üí      const data = JSON.parse(event.data);
   443‚Üí
   444‚Üí      // Invalidate relevant queries
   445‚Üí      queryClient.invalidateQueries({ queryKey: ['schedule', scheduleId] });
   446‚Üí
   447‚Üí      // Call custom handler
   448‚Üí      onUpdate?.(data);
   449‚Üí    };
   450‚Üí
   451‚Üí    eventSource.onerror = (error) => {
   452‚Üí      console.error('SSE error:', error);
   453‚Üí      eventSource.close();
   454‚Üí    };
   455‚Üí
   456‚Üí    return () => {
   457‚Üí      eventSource.close();
   458‚Üí    };
   459‚Üí  }, [scheduleId, queryClient, onUpdate]);
   460‚Üí}
   461‚Üí```
