### Gantt Chart

```tsx
// components/schedule/ScheduleGantt.tsx
import ReactECharts from 'echarts-for-react';
import { useMemo } from 'react';

interface ScheduleEvent {
  id: string;
  assetId: string;
  assetName: string;
  maintenanceType: string;
  startDate: Date;
  endDate: Date;
  status: 'scheduled' | 'in_progress' | 'completed';
}

interface ScheduleGanttProps {
  events: ScheduleEvent[];
  assets: string[];
  startDate: Date;
  endDate: Date;
  onEventClick?: (event: ScheduleEvent) => void;
}

export function ScheduleGantt({
  events,
  assets,
  startDate,
  endDate,
  onEventClick
}: ScheduleGanttProps) {
  const option = useMemo(() => ({
    tooltip: {
      trigger: 'item',
      formatter: (params: any) => {
        const event = events[params.dataIndex];
        return `
          <strong>${event.assetName}</strong><br/>
          ${event.maintenanceType}<br/>
          ${formatDate(event.startDate)} - ${formatDate(event.endDate)}
        `;
      }
    },
    grid: {
      left: 150,
      right: 20,
      top: 40,
      bottom: 40
    },
    xAxis: {
      type: 'time',
      min: startDate.getTime(),
      max: endDate.getTime(),
      axisLabel: {
        formatter: '{MMM} {d}'
      }
    },
    yAxis: {
      type: 'category',
      data: assets,
      axisLabel: {
        width: 140,
        overflow: 'truncate'
      }
    },
    series: [{
      type: 'custom',
      renderItem: (params: any, api: any) => {
        const event = events[params.dataIndex];
        const yIndex = assets.indexOf(event.assetName);

        const start = api.coord([event.startDate.getTime(), yIndex]);
        const end = api.coord([event.endDate.getTime(), yIndex]);

        const rectHeight = api.size([0, 1])[1] * 0.6;

        return {
          type: 'rect',
          shape: {
            x: start[0],
            y: start[1] - rectHeight / 2,
            width: end[0] - start[0],
            height: rectHeight
          },
          style: {
            fill: getEventColor(event.status),
            stroke: '#333',
            lineWidth: 1
          }
        };
      },
      data: events.map((e, i) => [e.startDate, e.endDate, i])
    }]
  }), [events, assets, startDate, endDate]);

  return (
    <ReactECharts
      option={option}
      style={{ height: Math.max(400, assets.length * 30) }}
      onEvents={{
        click: (params: any) => {
          if (onEventClick && params.dataIndex !== undefined) {
            onEventClick(events[params.dataIndex]);
          }
        }
      }}
    />
  );
}

function getEventColor(status: string): string {
  switch (status) {
    case 'completed': return '#10b981';
    case 'in_progress': return '#3b82f6';
    case 'scheduled': return '#f59e0b';
    default: return '#6b7280';
  }
}
